html:
{%- macro money(v) -%}{{ frappe.utils.fmt_money(v or 0, currency="INR") }}{%- endmacro -%}
{%- set subtotal = (doc.items | sum(attribute="amount")) or 0 -%}
{%- set tax = (doc.total or 0) - subtotal -%}

<style>
  .pi{
color:#1a1d1f;
font-family:"Helvetica Neue",Arial,sans-serif;
font-size:11.5px;
line-height:1.45;
border:2px solid #0f4c5c;
padding:14px;
}
  .pi *{ box-sizing:border-box; }
  .pi table{ width:100%; border-collapse:collapse; }
  .pi .muted{ color:#6b7378; }
  .pi .accent{ color:#0f4c5c; }
  .pi .right{ text-align:right; }
  .pi .center{ text-align:center; }
  .pi .lbl{ font-size:8.5px; letter-spacing:.09em; text-transform:uppercase; color:#8a9096; font-weight:700; }
  .pi .val{ font-size:11.5px; color:#1a1d1f; }
  .pi .strong{ font-weight:700; }

  /* Header */
  .pi .head{
border:2px solid #0f4c5c;
border-bottom:3px solid #0f4c5c;
margin-bottom:12px;
}
  .pi .co-name{ font-size:21px; font-weight:800; color:#0f4c5c; letter-spacing:.02em; line-height:1.1; }
  .pi .co-tag{ font-size:9px; font-style:italic; color:#5f7d86; margin-top:2px; letter-spacing:.04em; }
  .pi .co-meta{ font-size:9.5px; color:#5a6167; margin-top:6px; }
  .pi .stamp{ text-align:right; }
  .pi .stamp .title{ font-size:15px; font-weight:800; letter-spacing:.14em; color:#0f4c5c; }
  .pi .pill{ display:inline-block; font-size:8px; letter-spacing:.1em; font-weight:700; text-transform:uppercase;
             padding:2px 8px; border-radius:10px; margin-top:6px;
             -webkit-print-color-adjust:exact; print-color-adjust:exact; }
  .pi .pill.ok{ background:#e6f2ee; color:#12694e; }
  .pi .pill.pending{ background:#fdeecd; color:#8a5b00; }
  .pi .stamp .no{ font-size:12.5px; font-weight:800; color:#1a1d1f; margin-top:8px; }
  .pi .stamp .dt{ font-size:9.5px; color:#6b7378; }

  /* Party cards */
  .pi .cards{ margin-top:14px; }
  .pi .card{
border:2px solid #0f4c5c;
border-radius:4px;
padding:10px;
vertical-align:top;
}
  .pi .card .who{ font-size:12px; font-weight:700; color:#1a1d1f; margin:1px 0 3px; }
  .pi .card .addr{ font-size:10px; color:#4b5257; white-space:pre-line; }
  .pi .card .gst{ font-size:9.5px; margin-top:5px; }
  .pi .gap{ width:12px; }

  /* Reference strip */
  .pi .refs{
margin-top:12px;
border:2px solid #0f4c5c;
border-collapse:collapse;
}
  .pi .refs td{
border:1px solid #888;
padding:8px;
width:25%;
}
  .pi .chip{ display:inline-block; font-size:8.5px; font-weight:700; letter-spacing:.05em; padding:1px 7px;
             border-radius:9px; border:1px solid #cfd6da; color:#5a6167; margin-right:4px; }
  .pi .chip.on{ background:#0f4c5c; color:#fff; border-color:#0f4c5c;
                -webkit-print-color-adjust:exact; print-color-adjust:exact; }

  /* Items */
  .pi .items{
margin-top:16px;
border:2px solid #0f4c5c;
border-collapse:collapse;
}
  .pi .items thead th{ background:#0f4c5c; color:#fff; font-size:9px; letter-spacing:.06em; text-transform:uppercase;
                       font-weight:700; padding:8px 9px; text-align:left;
                       -webkit-print-color-adjust:exact; print-color-adjust:exact; }
  .pi .items tbody td{
padding:8px 9px;
border:1px solid #999;
vertical-align:top;
font-size:10.5px;
}
  .pi .items tbody tr:nth-child(even) td{ background:#f7f9fa; -webkit-print-color-adjust:exact; print-color-adjust:exact; }
  .pi .items .sl{ width:4%; color:#8a9096; }
  .pi .items .desc{ width:46%; }
  .pi .items .desc .name{ font-weight:700; color:#1a1d1f; }
  .pi .items .desc .sub{ color:#6b7378; font-size:9.5px; white-space:pre-line; }
  .pi .items .num{ width:16%; text-align:right; white-space:nowrap; }
  .pi .items .per{ width:8%; text-align:center; color:#6b7378; }
  .pi .items .qty{ width:10%; text-align:right; }

  /* Totals + words */
  .pi .foot-split{ margin-top:14px; }
  .pi .words{ vertical-align:top; padding-right:18px; }
  .pi .words .lbl{ margin-bottom:3px; }
  .pi .words .amt-words{ font-size:11px; font-style:italic; color:#2b3135; }
  .pi .warranty-box{ margin-top:12px; font-size:10px; }
  .pi .tot{
width:46%;
vertical-align:top;
border:2px solid #0f4c5c;
}
  .pi .tot table td{ padding:6px 12px; font-size:11px; }
  .pi .tot .row td{ border-bottom:1px solid #eef1f2; }
  .pi .tot .row .k{ color:#5a6167; }
  .pi .tot .row .v{ text-align:right; font-weight:600; }
  .pi .tot .grand td{ border-top:2px solid #0f4c5c; font-weight:800; font-size:12px; color:#1a1d1f; }
  .pi .tot .bal td{ background:#0f4c5c; color:#fff; font-weight:800; font-size:12.5px;
                    -webkit-print-color-adjust:exact; print-color-adjust:exact; }
  .pi .tot .bal .k{ letter-spacing:.05em; }

  /* Footer */
  .pi .pay-terms{
margin-top:14px;
border:2px solid #0f4c5c;
padding:10px;
background:#f5f8f9;
font-size:10px;
}
  .pi .bankrow{
margin-top:18px;
border:2px solid #0f4c5c;
}
  .pi .bank td{ vertical-align:top; }
  .pi .bank .lbl{ margin-bottom:5px; }
  .pi .bank .line{ font-size:10px; padding:1px 0; }
  .pi .bank .line b{ color:#1a1d1f; }
  .pi .sign{ text-align:right; vertical-align:bottom; }
  .pi .sign .for{ font-size:10px; font-weight:700; color:#1a1d1f; }
  .pi .sign .space{ height:42px; }
  .pi .sign .auth{ font-size:9.5px; color:#6b7378; border-top:1px solid #b9c1c6; display:inline-block; padding-top:3px; min-width:150px; }
  .pi .branches{
margin-top:16px;
padding:8px;
border:2px solid #0f4c5c;
text-align:center;
font-size:8.5px;
color:#8a9096;
}
  .pi .branches .web{ color:#0f4c5c; font-weight:700; }
  .pi .ctrl{
padding:6px;
border:2px solid #0f4c5c;
border-top:none;
text-align:center;
font-size:7.5px;
color:#aeb5ba;
}
</style>

<div class="pi">

    <table class="head">
    <tr>
      <td style="width:62%; vertical-align:top;">
        <div class="co-name">ENERTECH UPS PVT. LTD.</div>
        <div class="co-tag">Answering All Power Needs</div>
        <div class="co-meta">
          S.No. 399/1-2, Plot No. 5, Bhare P.O, Ghotawade (Near Pirangut), Tal. Mulshi, Dist. Pune - 412 115<br>
          Ph. 020 22923172 / 20291172 &nbsp;&bull;&nbsp; finance@enertechups.com<br>
          <span class="strong">GSTIN</span> 27AAACE6766A1ZT &nbsp;&bull;&nbsp; <span class="strong">PAN</span> AAACE6766A
        </div>
      </td>
                                                                </tr>
  </table>

    <table class="cards">
    <tr>
      <td class="card" style="width:49%;">
        <div class="lbl accent">Consignee</div>
        <div class="who">{{ doc.customer_name or "" }}</div>
        <div class="addr">{{ doc.consignee_address or "" }}</div>
        {%- if doc.consignee_gstin %}<div class="gst"><span class="strong">GSTIN</span> {{ doc.consignee_gstin }}</div>{%- endif %}
      </td>
      <td class="gap"></td>
      <td class="card" style="width:49%;">
        <div class="lbl accent">Buyer{{ " (same as consignee)" if doc.buyer_same_as_consignee else "" }}</div>
        {%- if doc.buyer_same_as_consignee %}
          <div class="who">{{ doc.customer_name or "" }}</div>
          <div class="addr">{{ doc.consignee_address or "" }}</div>
          {%- if doc.consignee_gstin %}<div class="gst"><span class="strong">GSTIN</span> {{ doc.consignee_gstin }}</div>{%- endif %}
        {%- else %}
          <div class="who">{{ doc.buyer_name or "" }}</div>
          <div class="addr">{{ doc.address or "" }}</div>
          {%- if doc.buyer_gstin %}<div class="gst"><span class="strong">GSTIN</span> {{ doc.buyer_gstin }}</div>{%- endif %}
        {%- endif %}
      </td>
    </tr>
  </table>

    <table class="refs">
    <tr>
      <td>
        <div class="lbl">Buyer's Order No.</div>
        <div class="val">{{ doc.buyers_order_no or "—" }}</div>
      </td>
      <td>
        <div class="lbl">Order Date</div>
        <div class="val">{{ frappe.utils.formatdate(doc.buyers_order_date, "dd-MM-yyyy") if doc.buyers_order_date else "—" }}</div>
      </td>
      <td>
        <div class="lbl">Order Received Via</div>
        <div class="val">
          <span class="chip {{ 'on' if doc.by_po }}">PO</span>
          <span class="chip {{ 'on' if doc.by_verbal }}">Verbal</span>
          <span class="chip {{ 'on' if doc.by_email }}">Email</span>
        </div>
      </td>
      <td>
        <div class="lbl">Supplier's Ref</div>
        <div class="val">{{ doc.suppliers_ref or "—" }}</div>
      </td>
    </tr>
    <tr>
      <td>
        <div class="lbl">Delivery Note</div>
        <div class="val">{{ doc.delivery_note or "—" }}</div>
      </td>
      <td>
        <div class="lbl">Delivery Date</div>
        <div class="val">{{ frappe.utils.formatdate(doc.delivery_date, "dd-MM-yyyy") if doc.delivery_date else "—" }}</div>
      </td>
      <td>
        <div class="lbl">Dispatched Through</div>
        <div class="val">{{ doc.dispatched_through or "—" }}</div>
      </td>
      <td>
        <div class="lbl">Freight Terms</div>
        <div class="val">{{ doc.freight_terms or "—" }}</div>
      </td>
    </tr>
    {%- if doc.other_references %}
    <tr>
      <td colspan="4">
        <div class="lbl">Other Reference(s)</div>
        <div class="val">{{ doc.other_references }}</div>
      </td>
    </tr>
    {%- endif %}
  </table>

    <table class="items">
    <thead>
      <tr>
        <th class="sl">#</th>
        <th class="desc">Description of Goods</th>
        <th class="qty" style="text-align:right;">Qty</th>
        <th class="num" style="text-align:right;">Rate</th>
        <th class="per" style="text-align:center;">Per</th>
        <th class="num" style="text-align:right;">Amount</th>
      </tr>
    </thead>
    <tbody>
      {%- for row in doc.items %}
      <tr>
        <td class="sl">{{ loop.index }}</td>
        <td class="desc">
          <div class="name">{{ row.get('item_code') or row.get('item_name') or '' }}</div>
          <div class="sub">{{ row.get('description') or '' }}</div>
        </td>
        <td class="qty">{{ "{:g}".format(row.get('qty') or 0) }}</td>
        <td class="num">{{ money(row.get('rate')) }}</td>
        <td class="per">{{ row.get('uom') or '' }}</td>
        <td class="num">{{ money(row.get('amount')) }}</td>
      </tr>
      {%- endfor %}
    </tbody>
  </table>

    <table class="foot-split">
    <tr>
      <td class="words">
        <div class="lbl">Amount in Words</div>
        <div class="amt-words">{{ frappe.utils.money_in_words(doc.total or 0) }}</div>

        {%- if doc.warranty %}
        <div class="warranty-box"><span class="lbl">Warranty</span><br>{{ doc.warranty }}</div>
        {%- endif %}
      </td>
      <td class="tot">
        <table>
          <tr class="row">
            <td class="k">Sub Total</td>
            <td class="v">{{ money(subtotal) }}</td>
          </tr>
          {%- if tax > 0.5 %}
          <tr class="row">
            <td class="k">GST / Taxes</td>
            <td class="v">{{ money(tax) }}</td>
          </tr>
          {%- endif %}
          <tr class="grand">
            <td class="k">Total</td>
            <td class="v">{{ money(doc.total) }}</td>
          </tr>
          {%- if doc.advance_payment %}
          <tr class="row">
            <td class="k">Advance Payment</td>
            <td class="v">{{ money(doc.advance_payment) }}</td>
          </tr>
          {%- endif %}
          <tr class="bal">
            <td class="k">Balance Payment</td>
            <td class="v">{{ money(doc.balance_payment) }}</td>
          </tr>
        </table>
      </td>
    </tr>
  </table>

    {%- if doc.modeterms_of_payment %}
  <div class="pay-terms"><span class="lbl">Mode / Terms of Payment</span> &nbsp; {{ doc.modeterms_of_payment }}</div>
  {%- endif %}

    <table class="bankrow">
    <tr class="bank">
      <td style="width:60%;">
        <div class="lbl">Company's Bank Details</div>
        <div class="line"><b>Bank</b>&nbsp; Bank of Baroda</div>
        <div class="line"><b>A/c No.</b>&nbsp; 80120400000554</div>
        <div class="line"><b>IFSC</b>&nbsp; BARB0VJPIRA</div>
      </td>
      <td class="sign" style="width:40%;">
        <div class="for">For ENERTECH UPS PVT. LTD.</div>
        <div class="space"></div>
        <div class="auth">Authorised Signatory</div>
      </td>
    </tr>
  </table>

  <div class="branches">
    Branches: Ahmedabad &bull; Delhi &bull; Hyderabad &bull; Vizag &bull; Nagpur &bull; Aurangabad &bull; Bhopal &bull; Chennai &bull; Coimbatore &bull; Kochi
    &nbsp; | &nbsp; <span class="web">www.enertechups.com</span>
  </div>
  <div class="ctrl">Doc No. EUPL/MKTG/FR/02 &bull; Rev. 02 &bull; This is a proforma invoice and is not a tax invoice.</div>

</div>

{%- macro money(v) -%}
{{ frappe.utils.fmt_money(v or 0, currency="INR") }}
{%- endmacro -%}

{%- set subtotal = (doc.items | sum(attribute="amount")) or 0 -%}
{%- set cgst_total = (doc.items | sum(attribute="custom_cgst_amount")) or 0 -%}
{%- set sgst_total = (doc.items | sum(attribute="custom_sgst_amount")) or 0 -%}
{%- set igst_total = (doc.items | sum(attribute="custom_igst_amount")) or 0 -%}
{%- set grand_total = doc.total_with_gst or doc.total or 0 -%}
{%- set amount_in_words = frappe.utils.money_in_words(grand_total, "INR") -%}

<style>
@page {
    size: A4;
    margin: 10mm 10mm 12mm 10mm;
}

html, body {
    margin: 0;
    padding: 0;
    background: #fff;
    font-family: Arial, Helvetica, sans-serif;
    color: #222;
    font-size: 10px;
    height: 100%;
}

* {
    box-sizing: border-box;
}

/* ---------- OUTER CONTAINER LAYOUT SYSTEM ---------- */
.invoice-container {
    width: 100%;
    min-height: 100%;
    height: 100vh; /* Forces container to occupy full page height, pushing footer down */
    border-collapse: collapse;
    border: 2px solid #1c3f60;
}

.invoice-container > thead {
    display: table-header-group;
}

.invoice-container > tfoot {
    display: table-footer-group;
}

.header-wrapper-cell {
    padding: 0;
    border-bottom: 2px solid #1c3f60;
}

/* ---------- ISOLATED CLEAN COMPACT HEADER BLOCK ---------- */
.company-legal-name {
    font-size: 14px;
    font-weight: bold;
    color: #11466a;
    letter-spacing: .5px;
    text-align: center;
    text-transform: uppercase;
    margin-bottom: 2px;
}

.company-address {
    line-height: 1.4;
    font-size: 9px;
    text-align: center;
    color: #333;
}

/* ---------- METADATA BLOCK FLOW ---------- */
.meta-data-section {
    width: 100%;
    border-bottom: 2px solid #1c3f60;
}

.invoice-meta-divider {
    border: none;
    border-top: 1px solid #1c3f60;
    margin: 4px 0 0 0;
}

.invoice-meta-table {
    width: 100%;
    border-collapse: collapse;
}

.invoice-meta-table td {
    padding: 6px 10px;
    font-size: 9px;
    vertical-align: top;
    border-right: 1px solid #c9d6e0;
}

.invoice-meta-table td:last-child {
    border-right: none;
}

/* ---------- ITEM SPECIFICATIONS TABLE ---------- */
.items-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 8px;
}

.items-table th {
    background: #11466a;
    color: white;
    border: 1px solid #1c3f60;
    padding: 6px 4px;
    font-size: 9px;
    text-transform: uppercase;
}

.items-table td {
    border: 1px solid #999;
    padding: 5px 4px;
    font-size: 9px;
    line-height: 1.3;
    vertical-align: top;
}

.items-table tbody tr {
    page-break-inside: avoid;
    break-inside: avoid;
}

.items-table tbody tr:nth-child(even) {
    background: #fafafa;
}

/* Column Width Percentages */
.col-sl { width: 4%; text-align: center; }
.col-desc { width: 30%; word-break: break-word; }
.col-qty { width: 5%; text-align: right; }
.col-uom { width: 5%; text-align: center; }
.col-rate { width: 9%; text-align: right; }
.col-gst { width: 9%; text-align: right; }
.col-amount { width: 9%; text-align: right; font-weight: bold; }
.col-xyz { width: 10%; }

/* Blocks */
.info-table {
    width: 100%;
    border-collapse: collapse;
    border-bottom: 1px solid #1c3f60;
}

.info-table td {
    border: 1px solid #999;
    padding: 5px 8px;
    font-size: 9px;
    vertical-align: top;
}

.words-box {
    border: 1px solid #1c3f60;
}

.words-box-title {
    background: #11466a;
    color: #fff;
    padding: 4px 6px;
    font-size: 8px;
    font-weight: bold;
    text-transform: uppercase;
}

.words-box-content {
    padding: 6px 8px;
    font-size: 9px;
    font-weight: bold;
    text-transform: capitalize;
}

.totals-table {
    width: 100%;
    table-layout: fixed;
    border-collapse: collapse;
    box-sizing: border-box;
    border: 1px solid #1c3f60;
}

.totals-table td {
    padding: 4px 6px;
    border: none;
    border-bottom: 1px solid #eee;
    font-size: 9px;
    overflow: hidden;
    box-sizing: border-box;
}

.totals-table tr:last-child td {
    border-bottom: none;
}

.totals-table td.label {
    font-weight: bold;
    width: 55%;
}

.totals-table td.value {
    text-align: right;
    width: 45%;
    word-break: break-word;
}

.totals-table tr.grand-total td {
    font-weight: bold;
    background: #eef6fb;
    border-top: 1px solid #1c3f60;
}

.summary-financial-block {
    page-break-inside: avoid;
    break-inside: avoid;
    margin-top: 10px;
}

/* ---------- NATIVE STRUCTURAL PAGE BOTTOM FOOTER ---------- */
.footer-wrapper-cell {
    padding: 0;
    border-top: 2px solid #1c3f60;
    background: #fff;
}

.footer-inner-block {
    width: 100%;
    padding: 6px 12px;
}

.product-range-ribbon {
    background: #11466a;
    color: #fff;
    text-align: center;
    font-size: 8px;
    font-weight: bold;
    padding: 5px 6px;
    letter-spacing: .3px;
    width: 100%;
    margin-top: 4px;
}
</style>

<table class="invoice-container">
    <thead>
        <tr>
            <td class="header-wrapper-cell" style="border-bottom: 2px solid #1c3f60; border-top: none;">
                <table style="width:100%; border-collapse:collapse;">
                    <tr>
                        <td style="padding:10px 12px 8px 12px;">
                            <div class="company-legal-name">ENERTECH UPS PVT LTD</div>
                            <div class="company-address">
                                S.No.399/1-2, Plot No.5, Bhare P.O, Ghotawade, Tal. Mulshi, Dist. Pune – 412115<br>
                                Phone : 020-22923172 / 20291172 &nbsp;&nbsp;&nbsp;&nbsp; Email : finance@enertechups.com<br>
                                GSTIN : 27AAACE6766A1ZT &nbsp;&nbsp;&nbsp;&nbsp; PAN : AAACE6766A
                            </div>
                        </td>
                    </tr>
                </table>
            </td>
        </tr>
    </thead>

    <tbody>
        <tr>
            <td style="padding:0; vertical-align:top; height: 100%;">

                <div class="meta-data-section">
                    <table style="width:100%; border-collapse:collapse;">
                        <tr>
                            <td style="padding:6px 12px;">
                                <div style="font-size:13px; font-weight:bold; color:#11466a; text-transform:uppercase; text-align:center; letter-spacing: 0.5px;">
                                    PROFORMA INVOICE
                                </div>
                                <hr class="invoice-meta-divider">
                                <table class="invoice-meta-table">
                                    <tr>
                                        <td style="width:35%;">
                                            <div><b>Proforma Invoice No. :</b><br>{{ doc.name }}</div>
                                        </td>
                                        <td style="width:25%;">
                                            <div><b>Date :</b><br>{{ frappe.utils.formatdate(doc.date,"dd-MM-yyyy") if doc.date else "" }}</div>
                                        </td>
                                        <td style="width:40%;">
                                            <div><b>Doc No. :</b> {{ doc.document_no or "-" }}</div>
                                            <div style="margin-top:2px;"><b>Rev No. :</b> {{ doc.rev_no or "-" }}</div>
                                            <div style="margin-top:2px;"><b>Updated :</b> {{ frappe.utils.formatdate(doc.modified,"dd-MM-yyyy") if doc.modified else "" }}</div>
                                        </td>
                                    </tr>
                                </table>
                            </td>
                        </tr>
                    </table>
                </div>

                <table class="info-table">
                    <tr>
                        <td rowspan="6" style="width:45%; font-size:9px;">
                            <div style="font-size:10px; font-weight:bold; color:#11466a; margin-bottom:4px;">BUYER</div>
                            <div style="font-size:11px; font-weight:bold; line-height:1.2; margin-bottom:3px;">
                                {{ doc.buyer or doc.customer }}
