    /* --- Professional Table Styling --- */

    /* Main container for the table */
    .custom-quotation-table {
        font-family: Arial, sans-serif;
        color: #333;
        margin-top: 20px;
    }

    /* General table settings */
    .custom-quotation-table .table-bordered {
        width: 100%;
