    .custom-quotation-table thead tr {
        background-color: #f2f2f2; /* Light grey background for header */
        color: #222;
        text-align: center;
    }

    .custom-quotation-table th {
        padding: 12px 8px;
        font-weight: bold;
        border: 1px solid #cccccc; /* Darker, more opaque border */
    }

    /* Table body cell styling */
    .custom-quotation-table td {
        padding: 10px 8px;
        border: 1px solid #cccccc; /* Darker, more opaque border */
        vertical-align: top; /* Aligns content to the top of the cell */
    }

    /* Zebra-striping for better readability */
    .custom-quotation-table tbody tr:nth-child(even) {
        background-color: #f9f9f9; 
